import React, { useState } from 'react';

export default function TextFrom(props) {
    let handle= () =>{
        console.log("Upper case is clicked")
        let newText = this.text.toUpperCase();
        setText(newText)
    }
    let handleOnchange= (event) =>{
        console.log("clicked on change")
        setText(event.target.valve)
    }
    const [text, setText] = useState("Enter Your Text");
  return (
    <>
      <form>
        <div className="container my-3">
            <h1>{props.heading}</h1>
          <div className="form-group">
            <textarea className="form-control" id="myBox" value={this.text} onChange={handleOnchange} rows="6"></textarea>
          </div>
        <button type="button" className="btn btn-primary" onClick={handle}>ConvertToUpperCase</button>
        </div>
        <div className="container">
          <h1>Your Summary </h1>
          <p>Words is:{this.text.split(" ").length} and charachter is:{this.text.length}</p>
        </div>
      </form>
    </>
  );
}
